/**
 * Whole-book search. The locale-specific index is generated by scripts/build.js
 * and is fetched only when the reader first uses the search control.
 */

(function universalSearch(root, factory) {
    'use strict';
    const api = factory();
    if (typeof module === 'object' && module.exports) {
        module.exports = api;
        return;
    }
    root.BookSearch = api;
    api.autoInit();
}(typeof globalThis !== 'undefined' ? globalThis : this, function searchFactory() {
    'use strict';

    const MAX_RESULTS = 12;
    const MAX_QUERY_LENGTH = 128;
    const MAX_INDEX_ENTRIES = 20000;

    function normalize(value) {
        return String(value || '')
            .normalize('NFKC')
            .toLocaleLowerCase('en-US')
            .replace(/\s+/g, ' ')
            .trim();
    }

    function fieldScore(value, query, weights) {
        const normalized = normalize(value);
        if (!normalized || !query) return 0;
        if (normalized === query) return weights.exact;
        if (normalized.startsWith(query)) return weights.prefix;
        if (normalized.includes(query)) return weights.includes;
        return 0;
    }

    function scoreEntry(entry, query, locale) {
        const normalizedQuery = normalize(query).slice(0, MAX_QUERY_LENGTH);
        if (!normalizedQuery) return 0;
        let score = 0;
        score += fieldScore(entry.title, normalizedQuery, { exact: 300, prefix: 210, includes: 160 });
        if (normalize(entry.heading) !== normalize(entry.title)) {
            score += fieldScore(entry.heading, normalizedQuery, { exact: 260, prefix: 190, includes: 140 });
        }
        if (normalize(entry.chapter) !== normalize(entry.title)) {
            score += fieldScore(entry.chapter, normalizedQuery, { exact: 120, prefix: 90, includes: 60 });
        }
        score += fieldScore(entry.text, normalizedQuery, { exact: 210, prefix: 180, includes: 150 });
        for (const alias of Array.isArray(entry.aliases) ? entry.aliases : []) {
            score += fieldScore(alias, normalizedQuery, { exact: 240, prefix: 170, includes: 120 });
        }
        if (score === 0) return 0;
        if (entry.section === 'chapters') score += 400;
        else if (entry.section === 'appendices') score += 60;
        else if (entry.section === 'special') score += 30;
        if (entry.locale === locale) score += 20;
        return score;
    }

    function searchEntries(entries, query, locale, limit = MAX_RESULTS) {
        return (Array.isArray(entries) ? entries : [])
            .map((entry, order) => ({ entry, order, score: scoreEntry(entry, query, locale) }))
            .filter((candidate) => candidate.score > 0)
            .sort((left, right) => right.score - left.score || left.order - right.order)
            .slice(0, limit)
            .map((candidate) => candidate.entry);
    }

    function escapeRegex(value) {
        return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    }

    function highlightSegments(text, query) {
        const source = String(text || '');
        const trimmed = String(query || '').trim().slice(0, MAX_QUERY_LENGTH);
        if (!trimmed) return [{ text: source, match: false }];
        const expression = new RegExp(`(${escapeRegex(trimmed)})`, 'giu');
        return source.split(expression)
            .filter((part) => part !== '')
            .map((part) => ({ text: part, match: normalize(part) === normalize(trimmed) }));
    }

    function snippet(text, query, maxLength = 190) {
        const source = String(text || '').replace(/\s+/g, ' ').trim();
        if (source.length <= maxLength) return source;
        const normalizedSource = normalize(source);
        const normalizedQuery = normalize(query);
        const matchIndex = normalizedSource.indexOf(normalizedQuery);
        const start = Math.max(0, (matchIndex === -1 ? 0 : matchIndex) - 55);
        const end = Math.min(source.length, start + maxLength);
        return `${start > 0 ? '…' : ''}${source.slice(start, end)}${end < source.length ? '…' : ''}`;
    }

    function keyboardAction(key, activeIndex, resultCount) {
        if (key === 'Escape') return { type: 'close', index: -1 };
        if (resultCount < 1) return { type: 'none', index: -1 };
        if (key === 'ArrowDown') return { type: 'select', index: (activeIndex + 1 + resultCount) % resultCount };
        if (key === 'ArrowUp') return { type: 'select', index: activeIndex <= 0 ? resultCount - 1 : activeIndex - 1 };
        if (key === 'Home') return { type: 'select', index: 0 };
        if (key === 'End') return { type: 'select', index: resultCount - 1 };
        if (key === 'Enter' && activeIndex >= 0) return { type: 'activate', index: activeIndex };
        return { type: 'none', index: activeIndex };
    }

    function validateIndexPayload(payload, expectedLocale) {
        if (!payload || payload.schemaVersion !== 1 || payload.locale !== expectedLocale || !Array.isArray(payload.entries)) {
            throw new Error('Invalid search index payload');
        }
        if (payload.entryCount !== payload.entries.length) throw new Error('Search index entryCount mismatch');
        if (payload.entryCount > MAX_INDEX_ENTRIES) throw new Error('Search index entry limit exceeded');
        if (typeof payload.project !== 'string' || !/^[A-Za-z0-9._-]+$/.test(payload.project)) {
            throw new Error('Invalid search index project');
        }
        const urlPrefix = `/${payload.project}/`;
        for (const entry of payload.entries) {
            if (!entry || entry.locale !== expectedLocale || !entry.url.startsWith(urlPrefix)) {
                throw new Error('Invalid search index entry scope');
            }
            for (const field of ['id', 'title', 'chapter', 'heading', 'text']) {
                if (typeof entry[field] !== 'string') throw new Error(`Invalid search index entry field: ${field}`);
            }
            if (!Array.isArray(entry.aliases) || entry.aliases.some((alias) => typeof alias !== 'string')) {
                throw new Error('Invalid search index aliases');
            }
        }
        return payload.entries;
    }

    function createController(documentObject, windowObject, fetchFunction) {
        const input = documentObject.getElementById('search-input');
        const resultsBox = documentObject.getElementById('search-results');
        const status = documentObject.getElementById('search-status');
        if (!input || !resultsBox || !status) return null;

        const locale = input.dataset.locale;
        const indexUrl = input.dataset.indexUrl;
        let indexPromise = null;
        let entries = [];
        let visibleResults = [];
        let activeIndex = -1;
        let debounceTimer = null;

        function statusLabel(key, fallback) {
            return input.dataset[key] || fallback;
        }

        function setStatus(message) {
            status.textContent = message;
        }

        function setExpanded(expanded) {
            input.setAttribute('aria-expanded', expanded ? 'true' : 'false');
            resultsBox.hidden = !expanded;
            resultsBox.classList.toggle('active', expanded);
            if (!expanded) {
                activeIndex = -1;
                input.removeAttribute('aria-activedescendant');
            }
        }

        function ensureIndex() {
            if (!indexPromise) {
                indexPromise = fetchFunction(indexUrl, {
                    credentials: 'same-origin',
                    headers: { Accept: 'application/json' }
                }).then((response) => {
                    if (!response.ok) throw new Error(`Search index request failed: ${response.status}`);
                    return response.json();
                }).then((payload) => {
                    entries = validateIndexPayload(payload, locale);
                    return entries;
                }).catch((error) => {
                    indexPromise = null;
                    throw error;
                });
            }
            return indexPromise;
        }

        function appendHighlighted(parent, text, query) {
            for (const segment of highlightSegments(text, query)) {
                const node = segment.match
                    ? documentObject.createElement('mark')
                    : documentObject.createTextNode(segment.text);
                if (segment.match) node.textContent = segment.text;
                parent.appendChild(node);
            }
        }

        function selectResult(index) {
            const options = [...resultsBox.querySelectorAll('[role="option"]')];
            activeIndex = index;
            options.forEach((option, optionIndex) => {
                const selected = optionIndex === activeIndex;
                option.setAttribute('aria-selected', selected ? 'true' : 'false');
                option.classList.toggle('selected', selected);
            });
            const active = options[activeIndex];
            if (active) {
                input.setAttribute('aria-activedescendant', active.id);
                active.scrollIntoView({ block: 'nearest' });
            }
        }

        function render(query) {
            visibleResults = searchEntries(entries, query, locale);
            activeIndex = -1;
            input.removeAttribute('aria-activedescendant');
            resultsBox.replaceChildren();

            if (visibleResults.length === 0) {
                const empty = documentObject.createElement('div');
                empty.className = 'search-no-results';
                empty.setAttribute('role', 'option');
                empty.setAttribute('aria-disabled', 'true');
                empty.textContent = statusLabel('noResultsLabel', 'No matching results');
                resultsBox.appendChild(empty);
            } else {
                visibleResults.forEach((result, index) => {
                    const option = documentObject.createElement('a');
                    option.className = 'search-result-item';
                    option.id = `search-option-${index}`;
                    option.href = result.url;
                    option.setAttribute('role', 'option');
                    option.setAttribute('aria-selected', 'false');

                    const context = documentObject.createElement('span');
                    context.className = 'search-result-context';
                    context.textContent = result.chapter;
                    const title = documentObject.createElement('span');
                    title.className = 'search-result-title';
                    appendHighlighted(title, result.title, query);
                    const resultSnippet = documentObject.createElement('span');
                    resultSnippet.className = 'search-result-snippet';
                    appendHighlighted(resultSnippet, snippet(result.text, query), query);
                    option.append(context, title, resultSnippet);
                    resultsBox.appendChild(option);
                });
            }

            const countTemplate = statusLabel('resultCountLabel', '{count} results');
            setStatus(countTemplate.replace('{count}', String(visibleResults.length)));
            setExpanded(true);
        }

        function runSearch() {
            const query = input.value.trim();
            if (!query) {
                setExpanded(false);
                setStatus('');
                return;
            }
            setStatus(statusLabel('loadingLabel', 'Loading search index'));
            ensureIndex().then(() => render(query)).catch(() => {
                resultsBox.replaceChildren();
                setExpanded(false);
                setStatus(statusLabel('loadErrorLabel', 'The search index could not be loaded'));
            });
        }

        input.addEventListener('focus', () => {
            ensureIndex().catch(() => {});
            if (input.value.trim() && entries.length > 0) render(input.value.trim());
        });
        input.addEventListener('input', () => {
            windowObject.clearTimeout(debounceTimer);
            debounceTimer = windowObject.setTimeout(runSearch, 180);
        });
        input.addEventListener('keydown', (event) => {
            const action = keyboardAction(event.key, activeIndex, visibleResults.length);
            if (action.type === 'none') return;
            event.preventDefault();
            if (action.type === 'close') {
                setExpanded(false);
            } else if (action.type === 'select') {
                selectResult(action.index);
            } else if (action.type === 'activate') {
                const option = resultsBox.querySelectorAll('[role="option"]')[action.index];
                if (option && option.href) option.click();
            }
        });
        documentObject.addEventListener('click', (event) => {
            if (!event.target.closest('.search-container')) setExpanded(false);
        });

        return { ensureIndex, render, runSearch, selectResult };
    }

    function autoInit() {
        if (typeof document === 'undefined' || typeof window === 'undefined' || typeof fetch !== 'function') return;
        const initialize = () => createController(document, window, fetch.bind(window));
        if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', initialize);
        else initialize();
    }

    return {
        autoInit,
        createController,
        escapeRegex,
        highlightSegments,
        keyboardAction,
        normalize,
        scoreEntry,
        searchEntries,
        snippet,
        validateIndexPayload
    };
}));
